import React, { useState } from 'react';

const STEPS = ['Account', 'Contact', 'Review'];

export default function Wizard() {
  const [step, setStep] = useState(0);
  const [data, setData] = useState({ name: '', email: '', plan: 'free' });
  const [submitted, setSubmitted] = useState(false);

  const update = (patch) => setData((d) => ({ ...d, ...patch }));

  const validators = [
    () => data.name.trim().length > 0,
    () => /.+@.+\..+/.test(data.email),
    () => true,
  ];
  const valid = validators[step]();

  const next = () => valid && setStep((s) => Math.min(s + 1, STEPS.length - 1));
  const back = () => setStep((s) => Math.max(s - 1, 0));
  const submit = () => setSubmitted(true);

  if (submitted) {
    return (
      <div style={{ maxWidth: 360 }}>
        <p style={{ color: '#16a34a', fontWeight: 600 }}>✓ Submitted!</p>
        <pre style={{ background: '#f3f4f6', padding: 12, borderRadius: 8 }}>{JSON.stringify(data, null, 2)}</pre>
      </div>
    );
  }

  const field = { width: '100%', padding: 8, fontSize: 15, boxSizing: 'border-box', marginTop: 4 };

  return (
    <div style={{ maxWidth: 360 }}>
      <div style={{ display: 'flex', gap: 6, marginBottom: 16 }}>
        {STEPS.map((label, i) => (
          <div key={label} style={{ flex: 1, textAlign: 'center' }}>
            <div style={{ height: 6, borderRadius: 3, background: i <= step ? '#2563eb' : '#e5e7eb' }} />
            <small style={{ color: i === step ? '#2563eb' : '#888' }}>{label}</small>
          </div>
        ))}
      </div>

      {step === 0 && (
        <label>Name
          <input style={field} value={data.name} onChange={(e) => update({ name: e.target.value })} />
        </label>
      )}
      {step === 1 && (
        <label>Email
          <input style={field} value={data.email} onChange={(e) => update({ email: e.target.value })} placeholder="you@example.com" />
        </label>
      )}
      {step === 2 && (
        <div>
          <p><strong>Name:</strong> {data.name}</p>
          <p><strong>Email:</strong> {data.email}</p>
        </div>
      )}

      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 20 }}>
        <button onClick={back} disabled={step === 0} style={{ padding: '8px 16px', cursor: 'pointer' }}>Back</button>
        {step === STEPS.length - 1 ? (
          <button onClick={submit} style={{ padding: '8px 16px', cursor: 'pointer', background: '#16a34a', color: '#fff', border: 'none', borderRadius: 6 }}>Submit</button>
        ) : (
          <button onClick={next} disabled={!valid} style={{ padding: '8px 16px', cursor: 'pointer', background: valid ? '#2563eb' : '#9ca3af', color: '#fff', border: 'none', borderRadius: 6 }}>Next</button>
        )}
      </div>
    </div>
  );
}

