import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-wizard',
  template: `
    <div style="max-width: 360px;" *ngIf="!submitted; else doneTpl">
      <div style="display: flex; gap: 6px; margin-bottom: 16px;">
        <div *ngFor="let label of steps; let i = index" style="flex: 1; text-align: center;">
          <div style="height: 6px; border-radius: 3px;" [style.background]="i <= step ? '#2563eb' : '#e5e7eb'"></div>
          <small [style.color]="i === step ? '#2563eb' : '#888'">{{ label }}</small>
        </div>
      </div>

      <label *ngIf="step === 0">Name
        <input [value]="data.name" (input)="data.name = $any($event.target).value" style="width: 100%; padding: 8px; font-size: 15px; box-sizing: border-box; margin-top: 4px;" />
      </label>
      <label *ngIf="step === 1">Email
        <input [value]="data.email" (input)="data.email = $any($event.target).value" placeholder="you@example.com" style="width: 100%; padding: 8px; font-size: 15px; box-sizing: border-box; margin-top: 4px;" />
      </label>
      <div *ngIf="step === 2">
        <p><strong>Name:</strong> {{ data.name }}</p>
        <p><strong>Email:</strong> {{ data.email }}</p>
      </div>

      <div style="display: flex; justify-content: space-between; margin-top: 20px;">
        <button (click)="back()" [disabled]="step === 0" style="padding: 8px 16px; cursor: pointer;">Back</button>
        <button *ngIf="step === steps.length - 1; else nextBtn" (click)="submit()" style="padding: 8px 16px; cursor: pointer; background: #16a34a; color: #fff; border: none; border-radius: 6px;">Submit</button>
        <ng-template #nextBtn>
          <button (click)="next()" [disabled]="!valid" [style.background]="valid ? '#2563eb' : '#9ca3af'" style="padding: 8px 16px; cursor: pointer; color: #fff; border: none; border-radius: 6px;">Next</button>
        </ng-template>
      </div>
    </div>

    <ng-template #doneTpl>
      <div style="max-width: 360px;">
        <p style="color: #16a34a; font-weight: 600;">✓ Submitted!</p>
        <pre style="background: #f3f4f6; padding: 12px; border-radius: 8px;">{{ pretty }}</pre>
      </div>
    </ng-template>
  `,
})
export class WizardComponent {
  step = 0;
  submitted = false;
  steps = ['Account', 'Contact', 'Review'];
  data = { name: '', email: '', plan: 'free' };

  get valid(): boolean {
    if (this.step === 0) {
      return this.data.name.trim().length > 0;
    }
    if (this.step === 1) {
      return /.+@.+\..+/.test(this.data.email);
    }
    return true;
  }

  get pretty(): string {
    return JSON.stringify(this.data, null, 2);
  }

  next(): void {
    if (this.valid) {
      this.step = Math.min(this.step + 1, this.steps.length - 1);
    }
  }

  back(): void {
    this.step = Math.max(this.step - 1, 0);
  }

  submit(): void {
    this.submitted = true;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Multi-step Form Demo</h1>
      <app-wizard></app-wizard>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, WizardComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
